Future<T> withCrashReporting<T>(String source) {
  return then<T>((value) => value as T)
      .catchError((Object error, StackTrace stack) {
    CrashReporter.instance.record(
      error,
      stack,
      source: source,
      fatal: false,
    );
    throw error;
  });
}

